feature vatu {
    sub virama-sinh zerowidthjoiner ra-sinh by rasign-sinh;
    sub virama-sinh zerowidthjoiner ya-sinh by yasign-sinh;
    sub zerowidthjoiner virama-sinh by touch-sinh;
} vatu;

feature psts {
    lookup raSignAe {
        sub ra-sinh aesign-sinh by rAe-sinh;
        sub ra-sinh aaesign-sinh by rAae-sinh;
    } raSignAe;

    lookup raSignU {
        sub ra-sinh usign-sinh' by aesign-sinh;
        sub ra-sinh uusign-sinh' by aaesign-sinh;
    } raSignU;

} psts;

feature blws {
    lookup RakarTwiceReplacement {
        sub rasign-sinh rasign-sinh' by rasign-sinh.alone;
    } RakarTwiceReplacement;

    lookup RakarLigatures {
        sub da-sinh rasign-sinh by dRa-sinh;
        sub nda-sinh rasign-sinh by ndRa-sinh;
        sub nya-sinh rasign-sinh by nyRa-sinh;
        sub jnya-sinh rasign-sinh by jnyRa-sinh;
        sub nDa-sinh rasign-sinh by nDRa-sinh;
    } RakarLigatures;

    sub da-sinh usign-sinh by dU-sinh;
    sub da-sinh uusign-sinh by dUu-sinh;
    sub nda-sinh usign-sinh by ndU-sinh;
    sub nda-sinh uusign-sinh by ndUu-sinh;
