    sub lla-sinh usign-sinh by llU-sinh;
    sub sha-sinh usign-sinh by shU-sinh;
    sub sha-sinh uusign-sinh by shUu-sinh;
    sub ka-sinh usign-sinh by kU-sinh;
    sub ka-sinh uusign-sinh by kUu-sinh;
    sub ta-sinh usign-sinh by tU-sinh;
    sub ta-sinh uusign-sinh by tUu-sinh;
    sub bha-sinh usign-sinh by bhU-sinh;
    sub bha-sinh uusign-sinh by bhUu-sinh;
    sub ga-sinh usign-sinh by gU-sinh;
    sub ga-sinh uusign-sinh by gUu-sinh;
    sub nnga-sinh usign-sinh by nngU-sinh;
    sub nnga-sinh uusign-sinh by nngUu-sinh;
    sub @uSignAlt3Group usign-sinh' by usign-sinh.alt3;
    sub @uSignAlt3Group uusign-sinh' by uusign-sinh.alt3;
    sub @uSignAlt2Group usign-sinh' by usign-sinh.alt2;
    sub @uSignAlt2Group uusign-sinh' by uusign-sinh.alt2;
