    lookup RakarUSign {
        sub rasign-sinh usign-sinh' by aesign-sinh.low;
        sub rasign-sinh uusign-sinh' by aaesign-sinh.low;
        sub @daShapeGroup usign-sinh' by aesign-sinh.low;
        sub @daShapeGroup uusign-sinh' by aesign-sinh.low;
    } RakarUSign;

    lookup RakarAlternates {
        sub @rakarAlt3Group rasign-sinh' by rasign-sinh.alt3;
        sub @rakarVaShapeGroup rasign-sinh' by rasign-sinh.alt2;
        sub @rakarAlt1Group rasign-sinh' by rasign-sinh.alt1;
        sub @rakarAlt4Group rasign-sinh' by rasign-sinh.alt4;
        sub [la-sinh ra-sinh lla-sinh] rasign-sinh' by rasign-sinh.alone;
    } RakarAlternates;

} blws;

