@CombiningTopAccents = [acutecomb brevecomb caroncomb circumflexcomb dieresiscomb dotaccentcomb gravecomb hungarumlautcomb macroncomb ringcomb tildecomb];
# automatic
# Prefix: Languagesystems
feature ccmp {
    # zero.slash alternate
    lookup latnSoftDot {
        lookupflag UseMarkFilteringSet @CombiningTopAccents;
        sub [i j]' @CombiningTopAccents by [idotless jdotless];
    } latnSoftDot;

    lookup latnLigatures {
        # The following WAS in the liga, but I think it belongs here.
        #sub O ogonekcomb macron by Oogonekmacron;
        #sub o ogonekcomb macron by oogonekmacron;
        #sub o.sc ogonekcomb.sc macron.sc by oogonekmacron.sc;
        #sub o.sc ogonekcomb.sc by oogonek.sc;
        sub A ogonekcomb by Aogonek;
        sub a ogonekcomb by aogonek;
        sub E ogonekcomb by Eogonek;
        sub e ogonekcomb by eogonek;
        sub I ogonekcomb by Iogonek;
        sub i ogonekcomb by iogonek;
        sub U ogonekcomb by Uogonek;
        sub u ogonekcomb by uogonek;
        # IPA
    } latnLigatures;

    script latn;
    language dflt;
    lookup latnSoftDot;
    lookup latnLigatures;
    language CAT;
    lookup latnSoftDot;
    lookup latnLigatures;
    language MAH;
    lookup latnSoftDot;
    lookup latnLigatures;
    language MOL;
    lookup latnSoftDot;
    lookup latnLigatures;
    language NAV;
    lookup latnSoftDot;
    lookup latnLigatures;
    language ROM;
    lookup latnSoftDot;
    lookup latnLigatures;
    script grek;
    # Greek
    script cyrl;
    #sub afii10103 by afii10103dotless;
    #sub afii10105 by afii10105dotless;
} ccmp;

